INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('GDPR', 'General Data Protection Regulation er EUs personvernforordning. Den gir enkeltpersoner rett til innsyn, retting og sletting av egne personopplysninger, og stiller krav til hvordan virksomheter behandler og sikrer slike data.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('ITIL', 'Information Technology Infrastructure Library er et rammeverk med beste praksis for IT-tjenestestyring. ITIL beskriver prosesser for ûË levere, drifte og forbedre IT-tjenester pûË en strukturert og effektiv mûËte.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Rammeverk', 'Et rammeverk er en samling retningslinjer, prinsipper og metoder som gir struktur for hvordan et arbeid skal utfû¡res. Innen IT brukes rammeverk for alt fra utvikling til sikkerhet og tjenestestyring.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Entydighet', 'Entydighet betyr at et begrep, en beskjed eller en prosedyre bare kan tolkes pûË ûˋn mûËte. I IT-stû¡tte er entydighet viktig for ûË unngûË misforstûËelser mellom bruker og tekniker ved feilmelding eller veiledning.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Standardisering', 'Standardisering innebûÎrer ûË bruke felles regler, formater eller prosedyrer slik at systemer og personer kan samarbeide effektivt. Det reduserer feil og gjû¡r opplûÎring og stû¡tte enklere.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Fagterminologi', 'Fagterminologi er de spesifikke begrepene og uttrykkene som brukes innenfor et fagfelt. I IT er presis fagterminologi viktig for tydelig kommunikasjon mellom teknikere, leverandû¡rer og brukere.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Samhandlingsverktû¡y', 'Samhandlingsverktû¡y er digitale programmer som hjelper personer ûË jobbe sammen, f.eks. Microsoft Teams, Slack eller SharePoint. De stû¡tter kommunikasjon, deling av filer og felles oppgavelû¡sning pûË tvers av steder.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('AML', 'Anti-Money Laundering (AML) er regelverk og rutiner for ûË forebygge hvitvasking av penger. I IT-sammenheng handler det om systemer og prosedyrer som oppdager mistenkelige transaksjoner og sikrer etterlevelse av lovkrav.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Plikter', 'Plikter er oppgaver og ansvar en person eller organisasjon er lovpûËlagt eller kontraktsmessig forpliktet til ûË utfû¡re. I brukerstû¡tte gjelder det f.eks. ûË behandle henvendelser, ivareta personvern og fû¡lge interne retningslinjer.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Rettigheter', 'Rettigheter er det en person eller organisasjon lovlig har krav pûË. I IT-stû¡tte inkluderer dette brukernes rett til personvern, innsyn i egne data og tilgang til nû¡dvendige systemer og ressurser for ûË utfû¡re sitt arbeid.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Kartlegge', 'Kartlegge betyr ûË systematisk samle og analysere informasjon for ûË fûË oversikt over en situasjon. I brukerstû¡tte kartlegges brukerens problem ved hjelp av spû¡rsmûËl og observasjon fû¡r en lû¡sning foreslûËs.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Veiledninger', 'Veiledninger er skriftlige eller muntlige instruksjoner som hjelper brukere ûË utfû¡re oppgaver korrekt. Gode veiledninger er klare, stegvise og tilpasset mûËlgruppens kompetansenivûË.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Prosedyre', 'En prosedyre er en fastsatt, trinnvis fremgangsmûËte for ûË utfû¡re en bestemt oppgave. Prosedyrer sikrer at arbeid utfû¡res konsekvent og korrekt, og er viktige i stû¡tte, drift og sikkerhet.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Etiske retningslinjer', 'Etiske retningslinjer er regler og prinsipper som beskriver forventet atferd i en organisasjon. I IT-stû¡tte handler det om konfidensialitet, respektfull kommunikasjon, rettferdig behandling og ansvarlig bruk av data.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Kurs', 'Et kurs er et strukturert opplûÎringsopplegg med definert innhold og mûËl. I IT brukes kurs til ûË heve kompetansen til ansatte, f.eks. om nye systemer, sikkerhet eller programvare.', 1);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('%username%', '%username% er en miljû¡variabel i Windows som automatisk erstattes med den innloggede brukerens kontonavn. Den brukes i skript og GPO-er for ûË lage dynamiske stier, f.eks. til brukerens hjemmemappe.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Utvid', 'I Active Directory betyr ô¨utvidô£ ûË delegere administrative rettigheter til underordnede OU-er, eller ûË bygge ut katalogtjenesten med nye objekter, attributter og funksjoner for ûË dekke organisasjonens behov.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('AD', 'Active Directory (AD) er Microsofts katalogtjeneste for Windows-nettverk. Den lagrer informasjon om brukere, datamaskiner og ressurser, og styrer autentisering og autorisasjon i et domenemiljû¡.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Akseptansetesting', 'Akseptansetesting er den siste testfasen der kunden eller brukeren bekrefter at systemet oppfyller avtalte krav. Testen utfû¡res i et miljû¡ som ligner produksjon, og godkjenning gir grû¡nt lys for idriftsettelse.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Antivirus / antimalware', 'Antivirus- og antimalware-programvare oppdager, blokkerer og fjerner skadelig programvare fra en enhet. Den bruker signaturer og atferdsanalyse for ûË beskytte mot virus, trojaner, ransomware og andre trusler.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('API', 'Application Programming Interface (API) er et grensesnitt som lar programmer kommunisere med hverandre. Et API definerer hvilke forespû¡rsler som kan sendes, hvilke data som returneres og hvordan kommunikasjonen foregûËr.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Arv', 'I Active Directory betyr arv at GPO-innstillinger og tillatelser gjelder automatisk for underordnede OU-er. I programmering betyr arv at en underklasse overtar egenskaper og metoder fra en overordnet klasse.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Autentisering', 'Autentisering er prosessen med ûË bekrefte at en bruker eller enhet er den den utgir seg for ûË vûÎre. Det gjû¡res vanligvis med brukernavn og passord, sertifikater eller biometriske data.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Autorisasjon', 'Autorisasjon avgjû¡r hva en autentisert bruker har tilgang til. Etter innlogging kontrollerer systemet hvilke ressurser, mapper og funksjoner brukeren har lov til ûË bruke, basert pûË roller og tillatelser.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Backup- og gjenopprettingsrutiner', 'Rutiner for sikkerhetskopiering og gjenoppretting beskriver nûËr og hvordan data sikkerhetskopieres, hvor kopiene lagres og hvordan de gjenopprettes ved datatap. Gode rutiner sikrer rask og pûËlitelig gjenoppretting.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('BinûÎrtall', 'BinûÎrtall er tallsystemet med grunntall 2, som bare bruker sifrene 0 og 1. All data i datamaskiner lagres og behandles som binûÎrtall, og systemet brukes bl.a. til ûË representere IP-adresser og minneadresser.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Bit', 'En bit er den minste dataenheten i informatikk og har verdien 0 eller 1. ûINSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Brannmur (firewall)', 'En brannmur er et sikkerhets-system som overvûËker og filtrerer nettverkstrafikk etter definerte regler. Den beskytter nettverket mot uautorisert tilgang og skadelig trafikk fra internett eller interne kilder.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Brannmursregler', 'Brannmursregler er konfigurerte betingelser som bestemmer hvilken nettverkstrafikk som tillates eller blokkeres. Reglene spesifiserer IP-adresse, port og protokoll, og er grunnlaget for nettverkssikkerhet.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Broadcast', 'Broadcast er en nettverksmelding som sendes til alle enheter i et nettverk eller subnett samtidig. Det brukes f.eks. av DHCP nûËr en klient sû¡ker etter en server, siden klienten ikke kjenner serverens adresse.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Bruker', 'En bruker er en person med en konto i et system, f.eks. Active Directory. Brukerkontoen gir tilgang til ressurser og tjenester basert pûË tildelte rettigheter, gruppemedlemskap og policy-innstillinger.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Brukeradministrasjon', 'Brukeradministrasjon er oppgaven med ûË opprette, endre, deaktivere og slette brukerkontoer i et system. Det inkluderer ûË tildele rettigheter, sette passordpolicy og holde brukerlisten oppdatert.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Brukermal', 'En brukermal er en forhûËndskonfigurert brukerkonto i Active Directory som brukes som utgangspunkt nûËr nye kontoer opprettes. Malen inneholder standardinnstillinger for gruppe, OU, hjemmemappe og profilsti.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Brukerstû¡tte (first-line, second-line)', 'Brukerstû¡tte deles i linjer: first-line lû¡ser vanlige problemer raskt, second-line hûËndterer mer komplekse saker som ikke lû¡ses i fû¡rste linje. Slik struktur sikrer effektiv ressursbruk og god brukeropplevelse.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Byte', 'En byte bestûËr av 8 bit og er grunnenheten for lagring av data. En byte kan representere 256 ulike verdier (0ã255). Filstû¡rrelser og minnekapasitet mûËles i kilobyte, megabyte, gigabyte osv.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('CIDR', 'Classless Inter-Domain Routing (CIDR) er en metode for ûË angi IP-adresser og nettverksmasker kompakt, f.eks. 192.168.1.0/24. Tallet etter skrûËstreken angir antall bit brukt til nettverksdelen av adressen.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Container', 'En container er en lettvekts virtualiseringsmetode som pakker en applikasjon med alle dens avhengigheter. Containere kjû¡res isolert fra hverandre, men deler operativsystemets kjerne, noe som gjû¡r dem raske og portable.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('CPU', 'Central Processing Unit (CPU) er datamaskinens prosessor og utfû¡rer beregninger og instruksjoner. CPU-ens ytelse mûËles i klokkehastighet (GHz) og antall kjerner, og pûËvirker systemets totale hastighet.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Delt mappe', 'En delt mappe er en nettverksmappe som gjû¡res tilgjengelig for flere brukere via et nettverk. Tilgang styres med tillatelser, og den brukes til samarbeid og sentral lagring av filer i en organisasjon.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('DHCP', 'Dynamic Host Configuration Protocol (DHCP) er en nettverksprotokoll som automatisk tildeler IP-adresser og nettverksinnstillinger til enheter. Det eliminerer behovet for manuell konfigurasjon av hvert enkelt utstyr.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('DHCP ã Scope', 'Et DHCP-scope er et definert omrûËde av IP-adresser som DHCP-serveren kan dele ut til klienter. Scope-innstillingene inkluderer adresseomrûËde, subnet-maske, lease-tid og standardinnstillinger som gateway og DNS.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('ping, traceroute, netstat', 'Ping tester tilgjengelighet til en vert ved ûË sende ICMP-pakker. Traceroute viser ruten pakkene tar gjennom nettverket. Netstat viser aktive nettverkstilkoblinger og porter pûË en maskin. Alle brukes til feilsû¡king.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('DNS (Domain Name System)', 'DNS er internettets telefonkatalog og oversetter lesbare domenenavn (f.eks. vg.no) til IP-adresser. Uten DNS mûËtte brukere huske numeriske adresser for ûË nûË nettsteder og tjenester.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('DNS-oppslag', 'Et DNS-oppslag er prosessen der en enhet spû¡r en DNS-server om IP-adressen til et domenenavn. Svaret lagres midlertidig i cache for ûË gjû¡re fremtidige oppslag raskere og redusere nettverksbelastning.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Dokumentasjon', 'Dokumentasjon er skriftlig informasjon som beskriver et systems oppbygging, konfigurasjon og drift. God dokumentasjon er avgjû¡rende for feilsû¡king, opplûÎring og viderefû¡ring av kunnskap i en IT-avdeling.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('DriftshûËndbok', 'En driftshûËndbok er et dokument som beskriver hvordan et IT-system skal driftes, vedlikeholdes og feilsû¡kes. Den inneholder prosedyrer, kontaktlister, systemkart og rutiner for sikkerhetskopiering og oppdatering.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Driftsstû¡tte', 'Driftsstû¡tte er den delen av IT som holder systemer, nettverk og servere i gang. Det inkluderer overvûËking, feilretting, oppdatering og vedlikehold slik at brukere og tjenester fungerer stabilt og sikkert.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Endringslogg (change log)', 'En endringslogg er en kronologisk liste over alle endringer gjort i et system eller en konfigurasjon. Den gir sporbarhet, hjelper ved feilsû¡king og sikrer at alle involverte vet hva som er endret og nûËr.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Ethernet', 'Ethernet er den vanligste teknologien for kablede lokale nettverk (LAN). Den definerer standarder for kabeltilkobling, datarammer og overfû¡ringshastigheter, og brukes i de fleste bedriftsnettverk i dag.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Feilsû¡king (troubleshooting)', 'Feilsû¡king er en systematisk prosess for ûË finne ûËrsaken til et problem i et IT-system. Metoden innebûÎrer ûË identifisere symptomet, isolere ûËrsaken, teste lû¡sninger og dokumentere resultatet.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Fil- og mappetillatelser (ACL)', 'Access Control List (ACL) er en liste over hvem som har hvilke rettigheter til en fil eller mappe. Tillatelser som lese, skrive og kjû¡re tildeles brukere og grupper for ûË styre tilgangen til ressurser.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Forholdsmessighet', 'Forholdsmessighet er et prinsipp om at tiltak skal stûË i rimelig forhold til behovet. I IT-sikkerhet og GDPR betyr det at man ikke skal samle inn mer data eller iverksette strengere tiltak enn situasjonen krever.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('FTP/SFTP', 'FTP (File Transfer Protocol) brukes til ûË overfû¡re filer mellom klient og server. SFTP (SSH File Transfer Protocol) er den krypterte varianten og er den anbefalte metoden siden FTP sender data i klartekst.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Gjenoppretting (restore)', 'Gjenoppretting er prosessen med ûË hente tilbake data fra en sikkerhetskopi etter datatap eller systemfeil. En vellykket gjenoppretting krever at backup-rutiner er testet regelmessig og at kopiene er intakte.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('GPO', 'Group Policy Object (GPO) er en samling innstillinger i Active Directory som styrer bruker- og maskinkonfigurasjon. GPO-er brukes til ûË hûËndheve sikkerhetspolicyer, installere programvare og styre skrivebord.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Henvendelse/ticket', 'En henvendelse eller ticket er en registrert forespû¡rsel om hjelp i et IT-stû¡ttesystem. Den inneholder beskrivelse av problemet, prioritet og status, og brukes til ûË spore saker fra ûËpning til lû¡sning.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Hovedkort', 'Hovedkortet (motherboard) er datamaskinens primûÎre kretskort og kobler sammen CPU, RAM, lagring og periferiutstyr. Det bestemmer hvilke komponenter som kan brukes og styrer kommunikasjon mellom dem.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('HTTP/HTTPS', 'HTTP (HyperText Transfer Protocol) brukes til ûË overfû¡re websider mellom server og nettleser. HTTPS er den krypterte versjonen og sikrer at data ikke kan avlyttes eller endres under overfû¡ringen.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Hypervisor', 'En hypervisor er programvare som kjû¡rer og administrerer virtuelle maskiner pûË en fysisk server. Type 1 kjû¡rer direkte pûË maskinvare, type 2 kjû¡rer oppûË et operativsystem. Eksempler er VMware ESXi og VirtualBox.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Image / systemimage', 'Et systemimage er et fullstendig û¡yeblikksbilde av et operativsystem med alle innstillinger og programmer. Det brukes til rask utrulling av identiske maskinkonfigurasjoner eller gjenoppretting etter systemfeil.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Incident management', 'Incident management er ITIL-prosessen for ûË hûËndtere uplanlagte avbrudd i IT-tjenester. MûËlet er ûË gjenopprette normal drift sûË raskt som mulig med minst mulig konsekvenser for brukere og virksomhet.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Integrasjonstesting', 'Integrasjonstesting sjekker at flere moduler eller systemer fungerer korrekt sammen. Den avdekker feil i grensesnitt og kommunikasjon mellom komponenter, og utfû¡res etter at enhetstesting er gjennomfû¡rt.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('IP-adresse (IPv4, IPv6)', 'En IP-adresse er en unik numerisk adresse som identifiserer en enhet i et nettverk. IPv4 bruker 32-biters adresser (f.eks. 192.168.0.1), mens IPv6 bruker 128-biters adresser for ûË mû¡te behovet for flere adresser.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('ITIL (grunnleggende prinsipper)', 'ITILs grunnleggende prinsipper inkluderer ûË fokusere pûË verdi, starte der du er, jobbe helhetlig og forbedre kontinuerlig. Prinsippene gir veiledning uavhengig av metode og er kjernen i ITIL 4-rammeverket.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Kabeltyper (UTP, STP, fiber)', 'UTP er uskjermet tvunnet par-kabel, vanlig i LAN. STP har skjerming mot interferens. Fiberoptisk kabel overfû¡rer lys og brukes til hû¡y hastighet og lange distanser. Valg av kabel avhenger av avstand og stû¡ykrav.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Klient (arbeidsstasjon)', 'En klient er en datamaskin eller enhet som bruker tjenester fra en server i et nettverk. Arbeidsstasjon er en betegnelse pûË brukerens PC i et bedriftsmiljû¡, ofte koblet til domenet og administrert sentralt.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Konfigurasjonsstyring', 'Konfigurasjonsstyring handler om ûË registrere, kontrollere og vedlikeholde informasjon om IT-komponenter og deres innstillinger. Det gir oversikt over infrastrukturen og er grunnlag for endringsstyring og feilsû¡king.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Konsollkabler (serial)', 'Konsollkabler brukes til direkte administrasjon av nettverksutstyr som svitsjer og rutere via seriellport (RS-232). Tilkoblingen krever ikke IP-adresse og er viktig for oppsett og feilsû¡king uten nettverkstilgang.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Kravspesifikasjon', 'En kravspesifikasjon er et dokument som beskriver hva et system eller en lû¡sning skal gjû¡re. Den skiller mellom funksjonelle krav (hva systemet skal gjû¡re) og ikke-funksjonelle krav (ytelse, sikkerhet, brukervennlighet).', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Kryptering', 'Kryptering gjû¡r data uleselige for uvedkommende ved hjelp av en algoritme og nû¡kkel. Kun den med riktig nû¡kkel kan dekryptere dataene. Brukes til ûË beskytte lagrede data og kommunikasjon over nettverk.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Lagringsenheter (HDD, SSD, NAS)', 'HDD er en mekanisk harddisk med roterende plater. SSD er et flash-basert solid-state-drev, raskere og mer robust. NAS (Network Attached Storage) er en nettverkstilkoblet lagringsenhet for delt lagring i et nettverk.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('LAN (lokalt nettverk)', 'Local Area Network (LAN) er et nettverk som forbinder enheter innenfor et begrenset geografisk omrûËde, f.eks. et kontor eller en skole. LAN gir rask kommunikasjon og ressursdeling mellom tilkoblede enheter.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('LDAP', 'Lightweight Directory Access Protocol (LDAP) er en protokoll for ûË sû¡ke i og administrere katalogtjenester som Active Directory. Den brukes til autentisering og oppslag av bruker- og ressursinformasjon i nettverk.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Loggfiler', 'Loggfiler er automatisk genererte tekstfiler som registrerer hendelser i et system. De inneholder tidsstempler, feilmeldinger og brukeraktivitet, og er uunnvûÎrlige ved feilsû¡king, sikkerhetskontroll og revisjon.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Mac-adresse', 'En MAC-adresse (Media Access Control) er en unik 48-biters hardwareadresse tildelt et nettverkskort av produsenten. Den brukes pûË lag 2 i nettverksmodellen til ûË identifisere enheter i et lokalt nettverk.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Malware (virus, trojaner, ransomware)', 'Malware er skadelig programvare som kan skade, stjele data eller ta kontroll over systemer. Virus sprer seg selv, trojaner skjuler seg som legitim programvare, og ransomware krypterer data og krever lû¡sepenger.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Monitorering/overvûËking', 'Monitorering er kontinuerlig overvûËking av IT-systemer for ûË oppdage feil, ytelsesfall og sikkerhetshendelser i sanntid. Verktû¡y som Nagios, Zabbix og Grafana brukes til ûË varsle driftsansvarlige ved avvik.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('NAT (Network Address Translation)', 'NAT oversetter private IP-adresser i et lokalt nettverk til ûˋn offentlig IP-adresse mot internett. Det sparer offentlige adresser og gir et ekstra lag med sikkerhet ved ûË skjule interne adresser utenfra.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Nettverksmaske', 'Nettverksmasken (subnet mask) angir hvilken del av en IP-adresse som tilhû¡rer nettverket og hvilken del som identifiserer verten. F.eks. betyr 255.255.255.0 at de tre fû¡rste oktetene er nettverksdelen.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Oppdatering/patch', 'En oppdatering eller patch er en programvarefiks som retter feil, lukker sikkerhetshull eller legger til ny funksjonalitet. Regelmessig oppdatering er en av de viktigste tiltakene for ûË beskytte IT-systemer.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Oppstartslaster (bootloader)', 'En oppstartslaster er et lite program som kjû¡res rett etter at datamaskinen skrur seg pûË. Den laster operativsystemet inn i minnet og gir bruker mulighet til ûË velge OS ved oppstart, f.eks. GRUB i Linux.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('OU', 'Organizational Unit (OU) er en beholder i Active Directory som brukes til ûË organisere brukere, grupper og datamaskiner. OU-er gjû¡r det enkelt ûË delegere administrasjon og anvende GPO-er pûË deler av domenet.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Patchpanel', 'Et patchpanel er en montert enhet i et kabelskap der nettverkskabler fra hele bygningen samles og kobles til svitsjer. Det gir fleksibel og ryddig kabeladministrasjon og gjû¡r det enkelt ûË endre koblinger.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Periferiutstyr (skjerm, tastatur, skriver)', 'Periferiutstyr er enheter koblet til datamaskinen utenfra, som skjerm, tastatur, mus og skriver. De er ikke en del av selve datamaskinen, men nû¡dvendige for brukerinteraksjon og utskrift av informasjon.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Personvern (GDPR)', 'Personvern handler om enkeltpersoners rett til kontroll over egne personopplysninger. GDPR er EUs regelverk som pûËlegger organisasjoner ûË behandle data lovlig, transparent og sikkert, og gi brukere rettigheter.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Problem management', 'Problem management er ITIL-prosessen for ûË identifisere og fjerne rotûËrsaker til gjentakende hendelser. MûËlet er ûË forhindre fremtidige avbrudd, i motsetning til incident management som fokuserer pûË rask gjenoppretting.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('PSU (strû¡mforsyning)', 'Power Supply Unit (PSU) konverterer vekselstrû¡m fra stikkontakten til likestû¡m som datamaskinens komponenter bruker. Effekten mûËles i watt, og det er viktig at PSU-en har nok kapasitet til alle komponenter.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('RAID (nivûËer: 0, 1, 5, 10)', 'RAID kombinerer flere harddisker for ytelse eller redundans. RAID 0 gir hastighet uten redundans. RAID 1 speiler data. RAID 5 bruker paritet for feiltoleranse. RAID 10 kombinerer speiling og striping.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('RAM', 'Random Access Memory (RAM) er datamaskinens arbeidsminne der aktive programmer og data midlertidig lagres. Mer RAM gir bedre multitasking-ytelse. RAM er flyktig og tû¡mmes nûËr maskinen slûËs av.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Router', 'En ruter er en nettverksenhet som videresender datapakker mellom ulike nettverk basert pûË IP-adresser. Den kobler f.eks. et lokalt nettverk til internett og bestemmer den beste ruten for trafikken.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Server', 'En server er en datamaskin eller programvare som leverer tjenester til andre maskiner (klienter) i et nettverk. Servere kan hûËndtere filer, e-post, nettsteder, databaser og autentisering sentralt.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('SG', 'Security Group (SG) er i Active Directory en gruppe som brukes til ûË tildele tilgang til ressurser. Brukere legges til gruppen, og gruppen gis tillatelser til mapper, programmer eller andre objekter i nettverket.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Sikkerheitsidentifikator (SID)', 'Security Identifier (SID) er en unik streng i Windows som identifiserer brukere, grupper og datamaskiner. SID-en brukes internt av systemet til tilgangskontroll og er mer stabil enn kontonavnet.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Sikkerhetskopiering (backup)', 'Sikkerhetskopiering er prosessen med ûË lage kopier av data for ûË kunne gjenopprette dem ved tap. Backupene kan lagres lokalt, eksternt eller i skyen, og bû¡r testes jevnlig for ûË sikre at gjenoppretting fungerer.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Sikre protokoller (HTTPS, SSH)', 'Sikre protokoller krypterer kommunikasjonen mellom systemer. HTTPS krypterer webtransport via TLS. SSH (Secure Shell) gir sikker fjernadministrasjon av servere via kryptert terminal. Begge erstatter usikre alternativer.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Single Sign-On (SSO)', 'Single Sign-On lar brukere logge inn ûˋn gang og fûË tilgang til flere systemer og applikasjoner uten ûË mûËtte autentisere seg pûË nytt. Det forbedrer brukeropplevelsen og reduserer passordfatigue og stû¡ttehenvendelser.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Skript (Bash, PowerShell)', 'Et skript er en tekstfil med kommandoer som kjû¡res automatisk av et shell. Bash brukes i Linux/macOS, PowerShell i Windows. Skript brukes til ûË automatisere repeterende driftsoppgaver som brukeroppretting og backup.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('SLA (Service Level Agreement)', 'En SLA er en avtale mellom en tjenesteleverandû¡r og kunde som definerer forventet servicenivûË, f.eks. oppetid og responstid. SLA-en angir ogsûË konsekvenser dersom nivûËene ikke oppfylles.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('SMTP/IMAP/POP3', 'SMTP sender e-post fra avsender til mottakers server. IMAP lar klienten lese e-post direkte fra serveren og synkroniserer pûË tvers av enheter. POP3 laster ned e-post til lokalt, sletter den fra serveren som standard.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Switch', 'En svitsj er en nettverksenhet som videresender datarammer mellom enheter i et LAN basert pûË MAC-adresser. I motsetning til en hub sender svitsjen bare trafikk til riktig port, noe som gir bedre ytelse.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('TCP/IP-stakken', 'TCP/IP-stakken er en lagdelt modell for nettverkskommunikasjon med fire lag: nettverks-, internett-, transport- og applikasjonslag. Den definerer hvordan data pakkes, adresseres, overfû¡res og mottas.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Terminalserver / fjernskriving (RDP)', 'En terminalserver lar brukere koble seg til og bruke et sentralt Windows-skrivebord over nettverket. RDP (Remote Desktop Protocol) er protokollen som brukes til slik fjerntilgang, og krypterer trafikken.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Testmiljû¡', 'Et testmiljû¡ er en isolert kopi av produksjonsmiljû¡et som brukes til ûË teste endringer, oppdateringer og ny programvare fû¡r de rulles ut. Dette reduserer risikoen for feil og driftsstans i det aktive systemet.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('To-faktor autentisering (2FA)', 'To-faktor autentisering krever to ulike bevis pûË identitet ved innlogging, f.eks. passord og en engangskode fra mobil. Det gjû¡r det langt vanskeligere for angripere ûË fûË tilgang selv om passordet er kompromittert.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('TrûËdlû¡st aksesspunkt', 'Et trûËdlû¡st aksesspunkt (WAP) kobler trûËdlû¡se enheter til et kablet nettverk via Wi-Fi. Det plasseres strategisk for ûË gi dekning i et omrûËde, og konfigureres med SSID, kryptering og tilgangskontroll.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Type 1 vs type 2', 'Type 1-hypervisor (bare-metal) kjû¡rer direkte pûË maskinvaren uten underliggende OS, f.eks. VMware ESXi. Type 2-hypervisor kjû¡rer oppûË et operativsystem, f.eks. VirtualBox. Type 1 gir bedre ytelse og brukes i produksjon.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Vedlikeholdsplan', 'En vedlikeholdsplan beskriver planlagte aktiviteter for ûË holde IT-systemer oppdaterte og i god stand. Den inkluderer tidspunkter for oppdateringer, sikkerhetskopiering, hardware-sjekk og rydding i logger.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Tilgangsdiagram', 'Et tilgangsdiagram er en visuell fremstilling av hvem som har tilgang til hvilke ressurser i et nettverk. Det brukes til dokumentasjon, sikkerhetsgjennomgang og for ûË sikre at tilgangsrettigheter fû¡lger minste-privilegium-prinsippet.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Virtuell svitsj', 'En virtuell svitsj (vSwitch) er en programvarebasert nettverkssvitsj i et virtualiseringsmiljû¡. Den kobler virtuelle maskiner til hverandre og til det fysiske nettverket, og stû¡tter VLAN og tilgangskontroll.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('VLAN (Virtual LAN)', 'Et VLAN er et logisk separert nettverk innenfor et fysisk nettverk. Det brukes til ûË isolere trafikk mellom avdelinger, f.eks. administrasjon og produksjon, uten behov for separate fysiske nettverkskomponenter.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('VM', 'En virtuell maskin (VM) er en programvareemulering av en fysisk datamaskin som kjû¡rer sitt eget operativsystem. Flere VM-er kan kjû¡re pûË ûˋn fysisk server, noe som gir bedre ressursutnyttelse og fleksibilitet.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('WAN', 'Wide Area Network (WAN) er et nettverk som strekker seg over store geografiske omrûËder, f.eks. mellom byer eller land. Internett er verdens stû¡rste WAN, og bedrifter bruker WAN til ûË koble sammen kontorer.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('X:\\', 'X:\\ er en nettverksstasjon mappet til en delt ressurs pûË en server. Stasjonsbokstaven tildeles via GPO eller skript, og gir brukeren enkel tilgang til felles lagring som om det var en lokal disk.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('\\\\server\\felles', '\\\\server\\felles er en UNC-sti (Universal Naming Convention) som peker direkte til en delt mappe kalt ô¨fellesô£ pûË en server. UNC-stier brukes for ûË nûË nettverksressurser uten ûË gûË via en mappet stasjonsbokstav.', 2);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Wiki', 'En wiki er en nettbasert plattform der brukere samarbeider om ûË skrive og redigere innhold. I utviklingsprosjekter brukes wiki til intern dokumentasjon, rutiner og prosjektinformasjon som holdes oppdatert av teamet.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Innholdsfortegnelse', 'En innholdsfortegnelse er en liste over kapitlene eller delene i et dokument med tilhû¡rende sidetall. Den gir leseren oversikt og gjû¡r det enkelt ûË navigere i lengre tekniske dokumenter og rapporter.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Sitat', 'Et sitat er en ordrett gjengivelse av hva noen har sagt eller skrevet, markert med anfû¡rselstegn. I teknisk dokumentasjon brukes sitater for ûË referere nû¡yaktig til kildemateriale, standarder eller spesifikasjoner.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Kilde', 'En kilde er det materialet man henter informasjon fra, f.eks. en bok, nettside eller forskningsartikkel. ûINSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Referanse', 'En referanse er en oppfû¡ring som identifiserer en kilde, vanligvis i en kildeliste. Den inneholder informasjon som forfatter, tittel, ûËr og URL, slik at leseren kan finne og verifisere kilden selv.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Figurliste', 'En figurliste er en oversikt over alle figurer, bilder og illustrasjoner i et dokument med tittel og sidetall. Den plasseres vanligvis etter innholdsfortegnelsen og hjelper leseren ûË lokalisere visuelle elementer raskt.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Digitale trusler', 'Digitale trusler er potensielle hendelser som kan skade IT-systemer, data eller brukere. Eksempler er hacking, phishing, ransomware og DDoS-angrep. Kunnskap om trusler er fû¡rste steg i ûË beskytte systemer.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Verdier', 'I sikkerhetskontekst er verdier de ressursene en organisasjon û¡nsker ûË beskytte, f.eks. data, systemer og omdû¡mme. ûINSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('SûËrbarheter', 'En sûËrbarhet er en svakhet i et system, program eller prosess som kan utnyttes av en angriper. Eksempler er utdatert programvare, svake passord og feilkonfigurerte tilganger. SûËrbarhetsskanning avdekker slike svakheter.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Phishing', 'Phishing er et sosialt ingeniû¡rangrep der angripere sender falske e-poster eller meldinger for ûË lure ofre til ûË gi fra seg passord eller klikke pûË skadelige lenker. Det er en av de vanligste angrepsvektorene.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Brannmur', 'En brannmur er et system som overvûËker og filtrerer nettverkstrafikk basert pûË sikkerhetsregler. Den skiller betrodde og ubetrodde soner, og blokkerer uautorisert tilgang til systemer og tjenester.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('FormûËlsbegrensning', 'FormûËlsbegrensning er et GDPR-prinsipp som sier at personopplysninger kun kan brukes til det formûËlet de opprinnelig ble samlet inn for. Videre bruk til andre formûËl krever nytt grunnlag eller samtykke.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Dataminimering', 'Dataminimering er et GDPR-prinsipp som krever at man kun samler inn personopplysninger som er nû¡dvendige for det angitte formûËlet. Man skal unngûË ûË lagre mer data enn det som trengs for ûË utfû¡re oppgaven.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Lagringsbegrensning', 'Lagringsbegrensning er et GDPR-prinsipp om at personopplysninger ikke skal lagres lenger enn nû¡dvendig for formûËlet. Organisasjoner mûË ha rutiner for ûË slette eller anonymisere data nûËr de ikke lenger er nû¡dvendige.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('CIA-triaden', 'CIA-triaden er de tre grunnpilarene i informasjonssikkerhet: Konfidensialitet (kun autoriserte ser dataene), Integritet (data er korrekte og uendrede) og Tilgjengelighet (data er tilgjengelige nûËr de trengs).', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Ansvarlighet', 'Ansvarlighet (accountability) er et GDPR-prinsipp som krever at organisasjoner ikke bare etterlever regelverket, men ogsûË kan dokumentere og bevise etterlevelse. Det inkluderer internkontroll og logging av behandlingsaktiviteter.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Autentisering', 'Autentisering er prosessen der et system bekrefter at en bruker er den de hevder ûË vûÎre. Vanlige metoder er passord, PIN, biometri og sertifikater. Sterk autentisering bruker flere faktorer kombinert.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Autorisering', 'Autorisering bestemmer hva en autentisert bruker har tillatelse til ûË gjû¡re i et system. Det styres gjennom roller og rettigheter, og sikrer at brukere kun har tilgang til ressurser de har behov for.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Variabel', 'En variabel er et navngitt lagringssted i minnet som holder en verdi i et program. I Python opprettes variabler ved tilordning: navn = verdi. Verdien kan endres underveis i programkjû¡ringen.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Datatype', 'En datatype definerer hva slags verdi en variabel kan inneholde og hvilke operasjoner som er tillatt. Vanlige typer i Python er int (heltall), float (desimaltall), str (tekst) og bool (sann/usann).', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Liste', 'En liste i Python er en ordnet, muterbar samling av elementer skrevet med hakeparenteser: [1, 2, 3]. Elementer kan legges til, fjernes og endres. Lister kan inneholde ulike datatyper og er svûÎrt fleksible.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Tuppel', 'En tuppel i Python er en ordnet, umuterbar samling av elementer skrevet med runde parenteser: (1, 2, 3). Siden den ikke kan endres, er den raskere enn en liste og brukes der dataene ikke skal modifiseres.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Ordbok', 'En ordbok (dict) i Python er en samling av nû¡kkel-verdi-par skrevet med krû¡lleparenteser: {"navn": "Ola"}. Nû¡klene er unike og brukes til ûË hente verdier raskt. Ordbû¡ker er svûÎrt nyttige for strukturerte data.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Sett', 'Et sett i Python er en uordnet samling av unike elementer: {1, 2, 3}. Duplikater fjernes automatisk. Sett er nyttige for ûË sjekke om et element finnes, og for mengdeoperasjoner som union og snitt.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Beslutning', 'En beslutning i programmering er en if/elif/else-struktur som utfû¡rer ulik kode avhengig av om en betingelse er sann eller usann. Beslutninger styrer programflyten og er grunnleggende i all programmering.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Lû¡kke', 'En lû¡kke gjentar en kodeblokk flere ganger. for-lû¡kken itererer over en sekvens, mens while-lû¡kken kjû¡rer sûË lenge en betingelse er sann. Lû¡kker brukes til ûË behandle lister, filer og repeterende oppgaver.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Funksjon', 'En funksjon er en navngitt, gjenbrukbar kodeblokk definert med def i Python. Den kan ta inn parametere, utfû¡re en oppgave og returnere en verdi. Funksjoner gjû¡r koden mer strukturert og lesbar.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Parameter', 'En parameter er en variabel i funksjonens definisjon som angir hvilke inngangsverdier funksjonen forventer. Parametere spesifiseres i def-linjen og brukes inne i funksjonen til ûË utfû¡re beregninger.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Argument', 'Et argument er den faktiske verdien som sendes inn til en funksjon nûËr den kalles. Mens parameter er navnet i definisjonen, er argument verdien som gis ved kallet: resultat = legg_til(3, 5) ã her er 3 og 5 argumenter.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Pip', 'Pip er Pythons pakkehûËndterer og brukes til ûË installere, oppdatere og avinstallere biblioteker fra PyPI. Kommandoen pip install pakkenavn laster ned og installerer pakken slik at den kan importeres i prosjektet.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('F-strings', 'F-strings er en Python-syntaks for ûË sette inn variable verdier direkte i en tekststreng: f"Hei {navn}!". Strengen prefixes med f, og uttrykk i krû¡lleparenteser evalueres og settes inn automatisk ved kjû¡ring.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Indentering', 'Indentering betyr innrykk av kode med mellomrom eller tab. I Python er indentering obligatorisk og definerer hvilken kode som tilhû¡rer en blokk, f.eks. kroppen til en funksjon, lû¡kke eller if-setning.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Jupyter-labs', 'JupyterLab er et nettbasert utviklingsmiljû¡ for Python der kode skrives og kjû¡res i celler. Det er populûÎrt for dataanalyse og undervisning fordi man kan se resultater, grafer og tekst i samme dokument.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('ledetekst', 'Ledetekst (prompt) er teksten som vises i terminalen eller konsollen for ûË indikere at systemet venter pûË brukerinndata. I Python brukes input("Skriv inn navn: ") til ûË vise ledetekst og lese brukerens svar.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Assert', 'Assert er en Python-setning som sjekker om et uttrykk er sant, og kaster AssertionError hvis det er usant. Brukes mye i testing for ûË verifisere forventede resultater: assert summer(2,3) == 5.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('PyTest', 'PyTest er et populûÎrt testrammeverk for Python som gjû¡r det enkelt ûË skrive og kjû¡re automatiserte tester. Det oppdager automatisk testfunksjoner som starter med test_, og gir tydelige feilmeldinger ved testsvikt.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Rammeverk', 'Et rammeverk er en forhûËndslaget struktur av kode og verktû¡y som gir et utgangspunkt for utvikling. I Python er Flask et webrammeverk og PyTest et testrammeverk. Rammeverk sparer tid og fremmer god praksis.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Enhetstest', 'En enhetstest tester ûˋn enkelt funksjon eller metode isolert fra resten av systemet. MûËlet er ûË verifisere at den minste kodeenheten oppfû¡rer seg som forventet for ulike inngangsverdier, inkludert kanttilfeller.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Integrasjonstest', 'En integrasjonstest kontrollerer at to eller flere moduler fungerer korrekt sammen. Den avdekker feil i kommunikasjonen mellom komponenter, f.eks. at en funksjon kaller databasen riktig og tolker svaret korrekt.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Manuell testing', 'Manuell testing er en testmetode der en person manuelt utfû¡rer testtilfeller uten bruk av automatiseringsverktû¡y. Det er nyttig for utforskende testing og brukeropplevelse, men er tidkrevende og feilutsatt.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Automatisert testing', 'Automatisert testing bruker skript og verktû¡y som PyTest til ûË kjû¡re tester uten manuell innblanding. Det gir rask tilbakemelding ved kodeendringer, reduserer menneskelige feil og er essensielt i CI/CD-pipelines.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Versjonskontroll', 'Versjonskontroll er et system som registrerer og sporer alle endringer i kildekoden over tid. Det gjû¡r det mulig ûË gûË tilbake til tidligere versjoner, sammenligne endringer og samarbeide uten ûË overskrive hverandres arbeid.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Git', 'Git er et distribuert versjonskontrollsystem som lar utviklere spore endringer i kode, jobbe i parallelle grener og samarbeide. Det er bransjestandarden for versjonskontroll og brukes i nesten alle utviklingsprosjekter.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('"Working directory"', 'Working directory er mappen pûË din lokale maskin der du gjû¡r endringer i filer. I Git er det omrûËdet der du redigerer koden fû¡r endringene legges til staging area og til slutt committes til lokalt repository.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('"Staging area"', 'Staging area (indeks) er et midlertidig omrûËde i Git der du samler endringer du û¡nsker ûË ta med i neste commit. Du legger til filer med git add, slik at du kan velge nû¡yaktig hvilke endringer som inkluderes.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('"Local repository"', 'Local repository er den lokale Git-databasen pûË din maskin som lagrer hele historikken med commits og grener. Det er en fullstendig kopi av prosjektet og tillater arbeid uten nettverkstilgang.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Remote repository', 'Et remote repository er et Git-prosjekt lagret pûË en ekstern server, f.eks. GitHub. Teammedlemmer henter (pull) og sender (push) endringer til remote for ûË synkronisere arbeidet sitt med resten av teamet.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('GitHub', 'GitHub er en skybasert plattform for ûË lagre og samarbeide om Git-prosjekter. Den tilbyr funksjoner som pull requests, issues, og GitHub Actions for CI/CD, og er den mest brukte plattformen for ûËpen kildekode.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Gren', 'En gren (branch) i Git er en parallell versjon av koden der man kan utvikle funksjoner eller fikse feil uten ûË pûËvirke hovedgrenen. Grener slûËs sammen (merge) nûËr arbeidet er ferdig og testet.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Repository', 'Et repository (repo) er prosjektmappen som inneholder all kildekode, filer og hele Git-historikken. Det kan vûÎre lokalt pûË maskinen din eller eksternt pûË plattformer som GitHub eller GitLab.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('"git clone"', 'git clone er en Git-kommando som lager en lokal kopi av et eksternt repository. All kode og historikk lastes ned, og den nye mappen kobles automatisk til remote slik at man kan pushe og pulle endringer.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Tag', 'En tag i Git er en navngitt peker til et bestemt commit, vanligvis brukt til ûË markere utgivelser som v1.0.0. Tags er stabile og endres ikke, i motsetning til grener som beveger seg med nye commits.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Egenskap', 'I CSS er en egenskap (property) det visuelle aspektet man vil endre, f.eks. color, font-size eller margin. Egenskapen skrives fû¡r kolonet i en CSS-regel og bestemmer hva som skal stilsettes pûË elementet.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Verdi', 'I CSS er verdien det man tildeler en egenskap, f.eks. red i color: red eller 16px i font-size: 16px. Verdien skrives etter kolonet og bestemmer hvordan egenskapen skal se ut i nettleseren.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Selektorer', 'CSS-selektorer velger hvilke HTML-elementer som skal stilsettes. Eksempler er element-selektor (p), klasse-selektor (.knapp) og ID-selektor (#topp). Kombinasjoner gir mer presis kontroll over styling.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Property', 'Property (egenskap) i CSS er den stilistiske egenskapen man û¡nsker ûË endre pûË et element. Eksempler inkluderer background-color, border-radius og display. Propertyen kombineres alltid med en verdi i CSS-regler.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('HTML-kommentar', 'En HTML-kommentar er tekst som ikke vises i nettleseren, men er synlig i kildekoden: <!-- Dette er en kommentar -->. Den brukes til ûË forklare kode, deaktivere elementer midlertidig eller legge igjen notater.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('CSS-kommentar', 'En CSS-kommentar er tekst som ignoreres av nettleseren: /* Dette er en kommentar */. Den brukes til ûË forklare stilregler, organisere kode i seksjoner og midlertidig deaktivere regler under utvikling.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('HTML-struktur', 'HTML-struktur er den hierarkiske oppbygningen av en nettside med nû¡klede elementer: <!DOCTYPE html>, <html>, <head> og <body>. En korrekt struktur er grunnlaget for at nettlesere og sû¡kemotorer tolker siden riktig.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('"Inline CSS"', 'Inline CSS er styling skrevet direkte i et HTML-elements style-attributt: <p style="color:red;">. Det overstyrer andre CSS-regler, men anbefales ikke i stû¡rre prosjekter da det gjû¡r koden vanskeligere ûË vedlikeholde.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('"Intern CSS"', 'Intern CSS er styling skrevet i en <style>-tagg inne i <head>-seksjonen pûË ûˋn HTML-side. Det er nyttig for enkeltsidestyling, men ekstern CSS foretrekkes i stû¡rre prosjekter for bedre gjenbruk og vedlikehold.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('"Ekstern CSS"', 'Ekstern CSS er styling i en separat .css-fil koblet til HTML med <link rel="stylesheet" href="stil.css">. Det er den anbefalte metoden, da ûˋn CSS-fil kan style flere HTML-sider og gjû¡re vedlikehold enklere.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('alt', 'alt-attributtet i HTML gir en tekstlig beskrivelse av et bilde: <img alt="Hund som lû¡per">. Det vises nûËr bildet ikke lastes, og er avgjû¡rende for tilgjengelighet da skjermlesere leser alt-teksten for synshemmede.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('src', 'src-attributtet angir kilden (URL eller filsti) til et medie-element i HTML, f.eks. <img src="bilde.jpg"> eller <script src="app.js">. Uten src vet ikke nettleseren hvor den skal hente ressursen fra.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('ol', '<ol> er HTML-taggen for en ordnet liste der hvert element nummereres automatisk. Den brukes nûËr rekkefû¡lgen har betydning, f.eks. i stegvise instruksjoner. Hvert element i listen markeres med <li>-tagg.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('nav', '<nav> er et semantisk HTML-element som markerer en navigasjonsblokk med lenker til andre deler av siden eller nettstedet. Det hjelper skjermlesere og sû¡kemotorer ûË forstûË sidens struktur.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('.nav', '.nav er en CSS-klasse som brukes til ûË style navigasjonselementer. Klassen tildeles HTML-elementer med class="nav" og kan brukes til ûË definere utseende for menylenker, farger og layout i navigasjonen.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('a', '<a>-taggen er HTML-elementet for en hyperlenke. href-attributtet angir destinasjonen: <a href="https://eksempel.no">Klikk her</a>. Lenker kan peke til andre sider, seksjoner pûË samme side eller e-postadresser.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Tabell', 'I databaser er en tabell en strukturert samling av data organisert i rader og kolonner. Hver kolonne representerer en egenskap (attributt), og hver rad er ûˋn post. Tabeller er grunnenheten i relasjonsdatabaser.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Rad', 'En rad (post) i en databasetabell er ûˋn enkelt oppfû¡ring med verdier for alle kolonnene. Hver rad representerer ett dataobjekt, f.eks. ûˋn kunde eller ett produkt, og identifiseres unikt av primûÎrnû¡kkelen.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Kolonne', 'En kolonne (felt/attributt) i en databasetabell definerer ûˋn type informasjon som lagres for alle poster, f.eks. navn eller fû¡dselsdato. Kolonnen har en datatype som bestemmer hva slags data som tillates.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('ER-diagram', 'Et ER-diagram (Entity-Relationship) er en visuell modell av databasens struktur. Det viser entiteter (tabeller), attributter (felter) og relasjonene mellom dem, og brukes i planleggingsfasen av databasedesign.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Relasjon', 'En relasjon i en database beskriver sammenhengen mellom to tabeller, f.eks. en-til-mange. Den etableres med fremmednû¡kler og gjû¡r det mulig ûË koble og kombinere data fra ulike tabeller i spû¡rringer.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('DBMS', 'Database Management System (DBMS) er programvare som administrerer databaser. Det hûËndterer lagring, henting, sikkerhet og flerbrukertilgang. MySQL, PostgreSQL og SQLite er eksempler pûË populûÎre DBMS-er.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Relasjonsdatabase', 'En relasjonsdatabase organiserer data i tabeller med definerte relasjoner mellom dem. Den bruker SQL for spû¡rringer og hûËndhever dataintegritet gjennom nû¡kler og constraints. MySQL er et vanlig eksempel.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('MySQL-Server', 'MySQL Server er selve databaseserveren som lagrer og administrerer databaser. Den tar imot SQL-spû¡rringer fra klienter, utfû¡rer dem og returnerer resultatene. MySQL er en av verdens mest brukte ûËpen kildekode-databaser.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('MySQL-Workbench', 'MySQL Workbench er et grafisk verktû¡y for ûË administrere og designe MySQL-databaser. Det gir et visuelt grensesnitt for ûË skrive SQL, designe ER-diagrammer, administrere brukere og overvûËke serveren.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Schemas', 'Et schema (skjema) i MySQL er en navngitt samling av tabeller, visninger og andre databaseobjekter. Det tilsvarer selve databasen og brukes til ûË organisere og separere data for ulike applikasjoner eller prosjekter.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('PrimûÎrnû¡kkel', 'En primûÎrnû¡kkel er ett eller flere felt som unikt identifiserer hver rad i en tabell. Verdien mûË vûÎre unik og ikke NULL. PrimûÎrnû¡kkelen er grunnlaget for relasjoner til andre tabeller og for effektiv sû¡king.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Fremmednû¡kkel', 'En fremmednû¡kkel er et felt i en tabell som refererer til primûÎrnû¡kkelen i en annen tabell. Den etablerer relasjoner mellom tabeller og sikrer referanseintegritet, slik at man ikke kan slette en post som andre refererer til.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Surrogatnû¡kkel', 'En surrogatnû¡kkel er en kunstig, teknisk nû¡kkel uten forretningsmessig betydning, f.eks. en auto-increment ID. Den brukes nûËr naturlige nû¡kler er for komplekse eller ustabile, og sikrer stabilt og unikt identifikator.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Kandidatnû¡kkel', 'En kandidatnû¡kkel er en kolonne eller kombinasjon av kolonner som kunne fungert som primûÎrnû¡kkel, da verdiene er unike og ikke NULL. Av alle kandidatnû¡kler velges ûˋn som den faktiske primûÎrnû¡kkelen.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('CRUD', 'CRUD er forkortelsen for de fire grunnleggende databaseoperasjonene: Create (INSERT), Read (SELECT), Update (UPDATE) og Delete (DELETE). Alle applikasjoner som bruker databaser bygger pûË disse fire operasjonene.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Spû¡rring', 'En spû¡rring (query) er en SQL-setning som kommuniserer med databasen for ûË hente, legge til, endre eller slette data. SELECT-spû¡rringer returnerer data, mens INSERT, UPDATE og DELETE endrer innholdet i databasen.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Normalisering', 'Normalisering er prosessen med ûË organisere en database for ûË redusere redundans og forbedre dataintegriteten. Det gjû¡res gjennom normalformer (1NF, 2NF, 3NF) som stiller krav til tabellstruktur og avhengigheter.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Flask', 'Flask er et lettvekts webrammeverk for Python som brukes til ûË bygge webapplikasjoner og API-er. Det gir grunnleggende verktû¡y for ruting, templating og hûËndtering av HTTP-forespû¡rsler uten mye konfigurasjon.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Jinja2', 'Jinja2 er Flasks malsystem som lar deg sette Python-variabler og logikk inn i HTML-filer. Plassholdere som {{ variabel }} byttes ut med faktiske verdier nûËr siden rendres, noe som gir dynamisk innhold.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Plassholdere', 'Plassholdere i Jinja2 er utrykk omgitt av doble krû¡lleparenteser {{ }} i HTML-maler. De byttes ut med verdier fra Python-koden nûËr Flask rendrer malen, og muliggjû¡r dynamisk og gjenbrukbar HTML.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('render_template', 'render_template er en Flask-funksjon som laster en Jinja2-HTML-mal, setter inn variabler og returnerer den ferdige HTML-siden til nettleseren. Den brukes i rutefunksjoner for ûË vise dynamiske nettsider.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('redirect', 'redirect er en Flask-funksjon som sender brukeren til en annen URL. Den brukes f.eks. etter at et skjema er sendt inn, for ûË unngûË at siden lastes pûË nytt ved oppdatering. Vanligvis kombinert med url_for.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('"get"', 'GET er en HTTP-metode som henter data fra en server uten ûË endre noe. I Flask brukes GET til ûË vise sider og sende sû¡kedata via URL-parametere. Det er den vanligste metoden for ûË laste nettsider.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('"post"', 'POST er en HTTP-metode som sender data til serveren i forespû¡rselens kropp, f.eks. skjemadata. I Flask brukes POST til ûË ta imot og behandle brukerinndata som passord og skjemaer, siden dataene ikke vises i URL-en.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('@app.route', '@app.route er en Flask-dekorator som kobler en URL-sti til en Python-funksjon. NûËr en bruker besû¡ker den angitte URL-en, kjû¡res funksjonen og returnerer et svar, f.eks. en HTML-side.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('commit()', 'commit() er en metode i Python-databasebiblioteker som lagrer alle ventende databaseendringer permanent. Uten commit() vil INSERT, UPDATE og DELETE-operasjoner ikke bli lagret, og rulles tilbake ved avbrudd.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Databasedriver', 'En databasedriver er et bibliotek som lar Python kommunisere med en bestemt database. For MySQL brukes f.eks. mysql-connector-python. Driveren oversetter Python-kode til databasens eget kommunikasjonsprotokoll.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Kryptering', 'Kryptering er prosessen der data gjû¡res uleselige med en algoritme og nû¡kkel, slik at bare autoriserte kan lese dem. I webutvikling krypteres passordforbindelser (HTTPS/TLS) og sensitive data i databasen.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Hashing', 'Hashing er en enveisfunksjon som gjû¡r om data til en fast lengde av tegn (hash). Passord lagres som hash i databaser slik at de ikke kan leses direkte. bcrypt og SHA-256 er vanlige hash-algoritmer.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Frontend', 'Frontend er den delen av en webapplikasjon som brukeren ser og interagerer med i nettleseren. Det inkluderer HTML for struktur, CSS for design og JavaScript for interaktivitet. Brukervennlighet er sentralt.', 3);
INSERT INTO begrep (begrep, begrep_definisjon, fag_idfag) VALUES ('Backend', 'Backend er den delen av en webapplikasjon som kjû¡rer pûË serveren og hûËndterer logikk, databaser og autentisering. I Python brukes f.eks. Flask som backend-rammeverk til ûË behandle forespû¡rsler og returnere data.', 3);
